    def mock_node(state: LearningState) -> dict[str, Any]:
        return {
            "theory_result": {
                "concept_understanding": "a",
                "logic": "b",
                "critical_thinking": "c",
                "feedback": "d",
            },
            "history_memory": [{"role": "theory_agent", "content": "d"}],
        }

    g = StateGraph(LearningState)
    g.add_node("theory_agent", mock_node)
    g.add_edge(START, "theory_agent")
    g.add_edge("theory_agent", END)
    graph = g.compile()
    r = graph.invoke({"student_input": "x", "history_memory": []})
    assert r["theory_result"]["feedback"] == "d"
    assert len(r["history_memory"]) == 1


def test_main_graph_import() -> None:
    import llm_config  # noqa: F401
    from main_graph import main_graph

    def stub_node(state: LearningState) -> dict[str, Any]:
        return {
            "theory_result": {
                "concept_understanding": "a",
                "logic": "b",
                "critical_thinking": "c",
                "feedback": "d",
            },
            "history_memory": [{"role": "theory_agent", "content": "d"}],
        }

