    g = StateGraph(LearningState)
    g.add_node("theory_agent", stub_node)
    g.add_edge(START, "theory_agent")
    g.add_edge("theory_agent", END)
    g.compile().invoke({"student_input": "hi", "history_memory": []})


if __name__ == "__main__":
    test_reducer()
    test_mock_invoke()
    test_main_graph_import()
    print("OK", file=sys.stderr)

