"""DOCX 解析：提取段落与表格文本。"""

from __future__ import annotations

from pathlib import Path

from docx import Document as DocxDocument


def parse_docx_text(docx_path: str | Path) -> str:
    """从 Word 文档提取纯文本。"""
    path = Path(docx_path).resolve()
    if not path.is_file():
        raise FileNotFoundError(f"DOCX 不存在: {path}")
    if path.suffix.lower() != ".docx":
        raise ValueError(f"仅支持 .docx 文件: {path}")

    doc = DocxDocument(str(path))
    parts: list[str] = []

    for para in doc.paragraphs:
        text = (para.text or "").strip()
        if text:
            parts.append(text)

    for table in doc.tables:
        rows: list[str] = []
        for row in table.rows:
            cells = [(cell.text or "").strip() for cell in row.cells]
            if any(cells):
                rows.append("\t".join(cells))
        if rows:
            parts.append("\n".join(rows))

    return "\n\n".join(parts)

"""图片 OCR：使用 PaddleOCR 提取文字。"""

from __future__ import annotations

from pathlib import Path
from typing import Any

IMAGE_SUFFIXES = {".png", ".jpg", ".jpeg"}

_ocr_engine: Any | None = None


def _get_ocr_engine() -> Any:
    global _ocr_engine
    if _ocr_engine is None:
        from paddleocr import PaddleOCR

        _ocr_engine = PaddleOCR(use_angle_cls=True, lang="ch", show_log=False)
    return _ocr_engine


def _lines_from_ocr_result(result: list | None) -> list[str]:
    """从 PaddleOCR 返回结构中抽取文本行。"""
    if not result:
        return []
    lines: list[str] = []
    for page in result:
        if not page:
            continue
        for item in page:
            if not item or len(item) < 2:
                continue
            text_part = item[1]
            if isinstance(text_part, (list, tuple)) and text_part:
                line = str(text_part[0]).strip()
            elif isinstance(text_part, str):
                line = text_part.strip()
            else:
                continue
            if line:
                lines.append(line)
    return lines


def parse_image_text(image_path: str | Path) -> str:
    """对 PNG/JPG/JPEG 执行 OCR，返回识别文本。"""
    path = Path(image_path).resolve()
    if not path.is_file():
        raise FileNotFoundError(f"图片不存在: {path}")
    suffix = path.suffix.lower()
    if suffix not in IMAGE_SUFFIXES:
        raise ValueError(f"仅支持 {', '.join(sorted(IMAGE_SUFFIXES))} 图片: {path}")

    ocr = _get_ocr_engine()
    result = ocr.ocr(str(path), cls=True)
    lines = _lines_from_ocr_result(result)
    return "\n".join(lines)

"""文件路由：按类型自动解析并返回统一文本。"""

from __future__ import annotations

from enum import Enum
from pathlib import Path

from input.docx_parser import parse_docx_text
from input.image_ocr import IMAGE_SUFFIXES, parse_image_text
from input.pdf_parser import parse_pdf_text
from state import UploadedFile

SUFFIX_TO_KIND: dict[str, str] = {
    ".pdf": "pdf",
    ".docx": "docx",
    **{ext: "image" for ext in IMAGE_SUFFIXES},
}

CONTENT_TYPE_BY_KIND: dict[str, str] = {
    "pdf": "application/pdf",
    "docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
    "image": "image/*",
}

KIND_LABEL: dict[str, str] = {
    "pdf": "PDF",
    "docx": "DOCX",
    "image": "图片(OCR)",
}


class FileKind(str, Enum):
    PDF = "pdf"
    DOCX = "docx"
    IMAGE = "image"


def detect_file_kind(file_path: str | Path) -> FileKind:
    """根据扩展名识别文件类型。"""
    path = Path(file_path).resolve()
    if not path.is_file():
        raise FileNotFoundError(f"文件不存在: {path}")
    suffix = path.suffix.lower()
    kind = SUFFIX_TO_KIND.get(suffix)
    if kind is None:
        supported = ", ".join(sorted(SUFFIX_TO_KIND))
        raise ValueError(
            f"不支持的文件类型: {suffix or '(无扩展名)'}，"
            f"支持: {supported}"
        )
    return FileKind(kind)


def parse_file_text(file_path: str | Path) -> str:
    """解析任意支持格式，返回统一纯文本（不含来源头）。"""
    kind = detect_file_kind(file_path)
    path = Path(file_path).resolve()

    if kind == FileKind.PDF:
        return parse_pdf_text(path)
    if kind == FileKind.DOCX:
        return parse_docx_text(path)
    return parse_image_text(path)


def build_uploaded_file(file_path: str | Path) -> UploadedFile:
    """构造 uploaded_files 元数据。"""
    path = Path(file_path).resolve()
    kind = detect_file_kind(path)
    return {
        "name": path.name,
        "path": str(path),
        "content_type": CONTENT_TYPE_BY_KIND[kind.value],
    }


def format_student_input(file_path: str | Path, content: str) -> str:
    """为 LangGraph 包装带来源说明的正文。"""
    path = Path(file_path).resolve()
    kind = detect_file_kind(path)
    label = KIND_LABEL[kind.value]
    return f"【来源文件：{path.name} ({label})】\n\n{content}"


def load_file_for_graph(
    file_path: str | Path,
) -> tuple[str, list[UploadedFile]]:
    """
    解析文件并准备 LangGraph 初始状态字段。

    Returns
    -------
    student_input : 含来源标记的正文
    uploaded_files : 单文件元数据列表
    """
    path = Path(file_path).resolve()
    content = parse_file_text(path).strip()
    if not content:
        raise ValueError(f"文件未解析到有效文本: {path}")

    uploaded = build_uploaded_file(path)
    student_input = format_student_input(path, content)
    return student_input, [uploaded]

