"""监督路由智能体：支持多路由（如 theory + data 并行）。"""

from __future__ import annotations

from typing import Literal

from langchain_core.prompts import ChatPromptTemplate
from pydantic import BaseModel, Field, field_validator

import llm_config  # noqa: F401

from llm_config import get_chat_llm
from state import LearningState, VALID_ROUTES, normalize_routes

RouteType = Literal["theory", "practice", "data"]


class RouterOutput(BaseModel):
    """多路由结构化输出。"""

    routes: list[RouteType] = Field(
        min_length=1,
        max_length=3,
        description=(
            "需要执行的评估分支列表，元素为 theory / practice / data，"
            "可 1～3 个，例如 ['theory', 'data']"
        ),
    )

    @field_validator("routes", mode="before")
    @classmethod
    def normalize_routes_field(cls, value: object) -> list[str]:
        if value is None:
            return ["theory"]
        if isinstance(value, str):
            items = [value]
        elif isinstance(value, list):
            items = value
        else:
            return ["theory"]
        return normalize_routes(items)

    @property
    def primary_route(self) -> str:
        return self.routes[0]


SUPERVISOR_PROMPT = ChatPromptTemplate.from_messages(
    [
        (
            "system",
            "你是教育智能体系统的路由监督员，负责根据学生提交内容判断应进入哪些评估分支。\n"
            "你只能输出 json 结构化结果，字段 routes 为数组，元素只能是小写英文：\n"
            "- theory：理论分析、概念理解、原理阐述、论证逻辑、批判性思维\n"
            "- practice：实验实践、操作步骤、实验设计、动手操作、规范与安全\n"
            "- data：数据分析、统计处理、图表可视化、建模推断\n"
            "规则：\n"
            "1. 可返回 1～3 个分支；内容跨多域时应同时选择多个，例如 theory+data。\n"
            "2. 不要返回重复分支；按相关程度从高到低排序。\n"
            "3. 若仅涉及单一领域，只返回一个元素。",
        ),
        ("human", "学生提交内容：\n{student_input}"),
    ]
)


def build_supervisor_chain(
    model: str | None = None,
    temperature: float | None = None,
):
    llm = get_chat_llm(model=model, temperature=temperature)
    structured_llm = llm.with_structured_output(
        RouterOutput,
        method="json_mode",
    )
    return SUPERVISOR_PROMPT | structured_llm


def _format_api_error(exc: Exception) -> str:
    msg = str(exc)
    if "402" in msg or "Insufficient Balance" in msg:
        return "DeepSeek 账户余额不足（HTTP 402），请充值后重试。"
    if "401" in msg or "invalid_api_key" in msg.lower():
        return "API 密钥无效（HTTP 401），请检查 OPENAI_API_KEY。"
    return f"路由判断 API 调用失败。原始错误: {exc}"


def route_student_input(
    student_input: str,
    *,
    model: str | None = None,
    temperature: float | None = None,
) -> RouterOutput:
    chain = build_supervisor_chain(model=model, temperature=temperature)
    try:
        return chain.invoke({"student_input": student_input})
    except Exception as exc:
        raise RuntimeError(_format_api_error(exc)) from exc


def supervisor_node(state: LearningState) -> dict:
    student_input = (state.get("student_input") or "").strip()
    if not student_input:
        raise ValueError("student_input 不能为空")

    preset = state.get("routes")
    if preset:
        routes = normalize_routes(preset)
    else:
        result = route_student_input(student_input)
        routes = normalize_routes(result.routes)

    return {"routes": routes, "route": routes[0]}


__all__ = [
    "RouteType",
    "RouterOutput",
    "SUPERVISOR_PROMPT",
    "VALID_ROUTES",
    "build_supervisor_chain",
    "route_student_input",
    "supervisor_node",
]

"""Graph 层统一 RAG 检索：按多路由并行检索，写入 retrieved_contexts。"""

from __future__ import annotations

from collections.abc import Callable

from rag.data_rag import retrieve_data_context
from rag.practice_rag import retrieve_practice_context
from rag.theory_rag import retrieve_theory_context
from state import (
    LearningState,
    RetrieveContextNodeUpdate,
    format_merged_retrieved_context,
    get_active_routes,
    normalize_routes,
)

RetrieveFn = Callable[[str], str]

ROUTE_RETRIEVERS: dict[str, RetrieveFn] = {
    "theory": retrieve_theory_context,
    "practice": retrieve_practice_context,
    "data": retrieve_data_context,
}


def retrieve_context_for_route(route: str, query: str) -> str:
    route = normalize_routes(route)[0]
    return ROUTE_RETRIEVERS[route](query)


def retrieve_contexts_for_routes(
    routes: list[str],
    query: str,
) -> dict[str, str]:
    """为每条路由独立检索，返回 route -> context。"""
    contexts: dict[str, str] = {}
    for route in normalize_routes(routes):
        contexts[route] = ROUTE_RETRIEVERS[route](query)
    return contexts


def retrieve_context_node(state: LearningState) -> RetrieveContextNodeUpdate:
    student_input = (state.get("student_input") or "").strip()
    if not student_input:
        raise ValueError("student_input 不能为空")

    routes = get_active_routes(state)
    contexts = retrieve_contexts_for_routes(routes, student_input)
    return {
        "retrieved_contexts": contexts,
        "retrieved_context": format_merged_retrieved_context(contexts),
    }


__all__ = [
    "ROUTE_RETRIEVERS",
    "retrieve_context_for_route",
    "retrieve_context_node",
    "retrieve_contexts_for_routes",
]

