                ),
            }
        )
    except Exception as exc:
        raise RuntimeError(f"综合反馈生成失败: {exc}") from exc

    feedback = str(result.final_feedback)
    return {
        "final_feedback": feedback,
        "history_memory": [
            {"role": "synthesis_agent", "content": feedback},
        ],
    }


