"""长期记忆检索：从历史评估记录中提取上下文。"""

from __future__ import annotations

from pathlib import Path
from typing import Any

from memory.evaluation_store import list_evaluations, load_student_memory

EMPTY_MEMORY_HINT = "（该学生暂无历史评估记录。）"


def _format_routes(routes: object) -> str:
    if isinstance(routes, list) and routes:
        return ", ".join(str(r) for r in routes)
    if isinstance(routes, str) and routes:
        return routes
    return "未知"


def _summarize_result(result: Any, *, keys: tuple[str, ...]) -> str:
    if not isinstance(result, dict):
        return ""
    parts: list[str] = []
    for key in keys:
        value = result.get(key)
        if value is None or value == "":
            continue
        text = str(value).strip()
        if len(text) > 200:
            text = text[:200] + "..."
        parts.append(f"{key}: {text}")
    return "; ".join(parts)


def format_evaluation_summary(record: dict[str, Any], *, index: int | None = None) -> str:
    """将单条评估记录格式化为可读摘要。"""
    header_parts: list[str] = []
    if index is not None:
        header_parts.append(f"记录{index}")
    ts = record.get("timestamp", "")
    routes = _format_routes(record.get("routes") or record.get("route"))
    if ts:
        header_parts.append(ts)
    header_parts.append(f"路由[{routes}]")
    header = " | ".join(header_parts)

    lines = [header]
    preview = (record.get("student_input_preview") or "").strip()
    if preview:
        lines.append(f"作答摘要: {preview[:300]}")

    theory = _summarize_result(
        record.get("theory_result"),
        keys=("concept_understanding", "logic", "critical_thinking", "feedback"),
    )
    if theory:
        lines.append(f"理论: {theory}")

    practice = _summarize_result(
        record.get("practice_result"),
        keys=("experiment_design", "operation_standard", "problem_solving", "feedback"),
    )
    if practice:
        lines.append(f"实践: {practice}")

    data = _summarize_result(
        record.get("data_result"),
        keys=("data_analysis", "visualization", "modeling", "feedback"),
    )
    if data:
        lines.append(f"数据: {data}")

    feedback = (record.get("final_feedback") or "").strip()
    if feedback:
        fb = feedback[:400] + ("..." if len(feedback) > 400 else "")
        lines.append(f"综合反馈: {fb}")

    return "\n".join(lines)


def retrieve_recent_evaluations(
    student_id: str,
    *,
    k: int = 3,
    memory_dir: Path | None = None,
    exclude_evaluation_id: str | None = None,
) -> list[dict[str, Any]]:
    """检索最近 k 条评估记录（不含当前条时可传 exclude_evaluation_id）。"""
    if k <= 0:
        return []
    records = list_evaluations(student_id, memory_dir=memory_dir, limit=k + 5)
    if exclude_evaluation_id:
        records = [
            r for r in records if r.get("evaluation_id") != exclude_evaluation_id
        ]
    return records[-k:]


def retrieve_memory_context(
    student_id: str,
    *,
    k: int = 3,
    memory_dir: Path | None = None,
    query: str | None = None,
) -> str:
    """
    检索并格式化为可注入 Prompt 的长期记忆文本。

    query 非空时做简单关键词过滤（在作答摘要与综合反馈中匹配）。
    """
    try:
        records = list_evaluations(student_id, memory_dir=memory_dir)
    except FileNotFoundError:
        return EMPTY_MEMORY_HINT

    if not records:
        return EMPTY_MEMORY_HINT

    if query and query.strip():
        q = query.strip().lower()
        filtered: list[dict[str, Any]] = []
        for rec in records:
            blob = " ".join(
                [
                    str(rec.get("student_input_preview") or ""),
                    str(rec.get("final_feedback") or ""),
                ]
            ).lower()
            if q in blob:
                filtered.append(rec)
        records = filtered[-k:] if filtered else records[-k:]
    else:
        records = records[-k:]

    if not records:
        return EMPTY_MEMORY_HINT

    blocks = [
        format_evaluation_summary(rec, index=i + 1)
        for i, rec in enumerate(records)
    ]
    return "\n\n---\n\n".join(blocks)


def retrieve_student_profile(
    student_id: str,
    *,
    memory_dir: Path | None = None,
) -> dict[str, Any]:
    """返回学生记忆元信息（不含完整 evaluations 时可截断）。"""
    memory = load_student_memory(
        student_id, memory_dir=memory_dir, create_if_missing=True
    )
    evaluations = memory.get("evaluations") or []
    return {
        "student_id": memory.get("student_id"),
        "created_at": memory.get("created_at"),
        "updated_at": memory.get("updated_at"),
        "total_evaluations": len(evaluations),
        "recent_routes": [
            r.get("routes") for r in evaluations[-5:] if r.get("routes")
        ],
    }


__all__ = [
    "EMPTY_MEMORY_HINT",
    "format_evaluation_summary",
    "retrieve_memory_context",
    "retrieve_recent_evaluations",
    "retrieve_student_profile",
]

"""长期记忆管理器：评估写入 + 历史检索（不依赖 LangGraph 图内节点）。"""

from __future__ import annotations

from pathlib import Path
from typing import Any

from memory.evaluation_store import (
    DEFAULT_MEMORY_DIR,
    append_evaluation,
    build_evaluation_record,
    delete_student_memory,
    get_memory_path,
    list_evaluations,
    load_student_memory,
    sanitize_student_id,
    save_student_memory,
)
from memory.memory_retriever import (
    retrieve_memory_context,
    retrieve_recent_evaluations,
    retrieve_student_profile,
)


class MemoryManager:
    """
    学生长期记忆门面。

    - 每个 student_id 对应一个 JSON 文件（data/memory/students/{id}.json）
    - 图执行前后由入口层调用，不修改 graph 结构
    """

    def __init__(
        self,
        student_id: str,
        *,
        memory_dir: Path | str | None = None,
        max_records: int = 100,
        default_retrieve_k: int = 3,
    ) -> None:
        self.student_id = sanitize_student_id(student_id)
        self.memory_dir = Path(memory_dir) if memory_dir else DEFAULT_MEMORY_DIR
        self.max_records = max_records
        self.default_retrieve_k = default_retrieve_k

    @property
    def memory_path(self) -> Path:
        return get_memory_path(self.student_id, memory_dir=self.memory_dir)

    def load(self) -> dict[str, Any]:
        return load_student_memory(self.student_id, memory_dir=self.memory_dir)

    def save(self, memory: dict[str, Any]) -> Path:
        return save_student_memory(
            self.student_id, memory, memory_dir=self.memory_dir
        )

    def record_evaluation(
        self,
        state: dict[str, Any],
        *,
        extra: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        """从 LangGraph 返回的 state dict 追加一条评估记录。"""
        record = build_evaluation_record(
            student_input=str(state.get("student_input") or ""),
            routes=state.get("routes"),
            route=state.get("route"),
            theory_result=state.get("theory_result"),
            practice_result=state.get("practice_result"),
            data_result=state.get("data_result"),
            final_feedback=state.get("final_feedback"),
            history_memory=state.get("history_memory"),
            uploaded_files=state.get("uploaded_files"),
            extra=extra,
        )
        return append_evaluation(
            self.student_id,
            record,
            memory_dir=self.memory_dir,
            max_records=self.max_records,
        )

    def get_recent(self, k: int | None = None) -> list[dict[str, Any]]:
        return retrieve_recent_evaluations(
            self.student_id,
            k=k or self.default_retrieve_k,
            memory_dir=self.memory_dir,
        )

    def get_context(
        self,
        *,
        k: int | None = None,
        query: str | None = None,
    ) -> str:
        """检索格式化的长期记忆文本。"""
        return retrieve_memory_context(
            self.student_id,
            k=k or self.default_retrieve_k,
            memory_dir=self.memory_dir,
            query=query,
        )

    def enrich_student_input(
        self,
        student_input: str,
        *,
        k: int | None = None,
        query: str | None = None,
    ) -> str:
        """
        将长期记忆前置到学生输入（供入口层注入，不修改 graph）。

        若无历史记录则原样返回 student_input。
        """
        context = self.get_context(k=k, query=query or student_input)
        if context.startswith("（该学生暂无"):
            return student_input
        return (
            f"【学生历史评估记忆 — {self.student_id}】\n{context}\n\n"
            f"【本次提交】\n{student_input}"
        )

    def profile(self) -> dict[str, Any]:
        return retrieve_student_profile(
            self.student_id, memory_dir=self.memory_dir
        )

    def list_all(self, limit: int | None = None) -> list[dict[str, Any]]:
        return list_evaluations(
            self.student_id,
            memory_dir=self.memory_dir,
            limit=limit,
        )

    def clear(self) -> bool:
        return delete_student_memory(self.student_id, memory_dir=self.memory_dir)


def record_evaluation_for_student(
    student_id: str,
    state: dict[str, Any],
    *,
    memory_dir: Path | None = None,
    max_records: int = 100,
) -> dict[str, Any]:
    """便捷函数：保存单次评估。"""
    return MemoryManager(
        student_id, memory_dir=memory_dir, max_records=max_records
    ).record_evaluation(state)


def get_memory_context_for_student(
    student_id: str,
    *,
    k: int = 3,
    query: str | None = None,
    memory_dir: Path | None = None,
) -> str:
    """便捷函数：检索长期记忆文本。"""
    return MemoryManager(
        student_id, memory_dir=memory_dir, default_retrieve_k=k
    ).get_context(k=k, query=query)


__all__ = [
    "MemoryManager",
    "get_memory_context_for_student",
    "record_evaluation_for_student",
]

